# Avatar height control — floating window. Toggle with Ctrl+Shift+H.
bind_hotkey("Ctrl+Shift+H")

state = {"loop": False}

ext_clear()
ext_label("Avatar height (metres)")
field = ext_text("Height", "1.8")

def apply():
    try:
        set_height(float(field.value)); print("Set height ->", field.value)
    except Exception as e:
        print("Invalid height:", e)

def set_loop(v):
    state["loop"] = bool(v)
    print("Loop set-height:", "ON" if state["loop"] else "OFF")

ext_button("Apply", apply)
ext_button("Reset 1.8m", lambda: set_height(1.8))
ext_toggle("Loop (keep re-applying)", set_loop)
ext_show()

while True:
    if state["loop"]:
        try: set_height(float(field.value))
        except Exception: pass
    await wait(0.08)
